func (h *handler) ListChannels() ListChannelsHandler {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, r *http.Request, params ListChannelsParams) (ListChannelsRequest, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil { return ListChannelsRequest{}, err }
			return ListChannelsRequest{Namespaces: []string{ns}, Page: pagination.Page{PageSize: lo.FromPtrOr(params.PageSize, notification.DefaultPageSize)}}, nil
		},
		func(ctx context.Context, req ListChannelsRequest) (ListChannelsResponse, error) {
			resp, err := h.service.ListChannels(ctx, req)
			/* map resp.Items via FromChannel */ return ListChannelsResponse{}, err
		},
		commonhttp.JSONResponseEncoderWithStatus[ListChannelsResponse](http.StatusOK),
		httptransport.AppendOptions(h.options, httptransport.WithOperationName("listNotificationChannels"), httptransport.WithErrorEncoder(errorEncoder()))...,
	)
}

func (t *TestEventGenerator) Generate(ctx context.Context, in EventGeneratorInput) (notification.EventPayload, error) {
	if err := in.Validate(); err != nil { return notification.EventPayload{}, err }
	switch in.EventType {
	case notification.EventTypeBalanceThreshold:
		return t.newTestBalanceThresholdPayload(), nil
	case notification.EventTypeInvoiceCreated, notification.EventTypeInvoiceUpdated:
		return t.newTestInvoicePayload(ctx, in.Namespace, in.EventType)
	default:
		return notification.EventPayload{}, fmt.Errorf("unsupported event type: %s", in.EventType)
	}
}

func (s Service) CreateChannel(ctx context.Context, params notification.CreateChannelInput) (*notification.Channel, error) {
	if err := params.Validate(); err != nil { return nil, fmt.Errorf("invalid params: %w", err) }
	fn := func(ctx context.Context) (*notification.Channel, error) {
		channel, err := s.adapter.CreateChannel(ctx, params)
		if err != nil { return nil, err }
		wb, err := s.webhook.CreateWebhook(ctx, webhook.CreateWebhookInput{Namespace: params.Namespace, ID: &channel.ID, URL: channel.Config.WebHook.URL})
		if err != nil { return nil, err }
		updateIn := notification.UpdateChannelInput{NamespacedID: models.NamespacedID{Namespace: params.Namespace, ID: channel.ID}, Config: channel.Config}
		updateIn.Config.WebHook.SigningSecret = wb.Secret
		return s.adapter.UpdateChannel(ctx, updateIn)
	}
	return transaction.Run(ctx, s.adapter, fn)
}
